static inline uint32_t CeilDiv(uint32_t a, uint32_t b)
{
    return (a + b - 1u) / b;
}
}

namespace optiling {

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    GemmScalingHardTanhGeluCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);

    // Expect shapes: x [M, K], w [N, K], b [N]
    const uint32_t M = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(0));
    const uint32_t K = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(1));
    const uint32_t N = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(0));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const float *scaling = attrs->GetAttrPointer<float>(0);
    const float *htMin = attrs->GetAttrPointer<float>(1);
    const float *htMax = attrs->GetAttrPointer<float>(2);

    // Conservative static tile sizes chosen for stability and simplicity
    uint32_t tileM = 64;
    uint32_t tileN = 8;

    uint32_t blockDim = CeilDiv(M, tileM);
    if (blockDim < 1u) blockDim = 1u;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.set_M(M);
    tiling.set_N(N);
    tiling.set_K(K);
    tiling.set_tileM(tileM);
    tiling.set_tileN(tileN);
    tiling.set_blockDim(blockDim);
    tiling.set_scaling(*scaling);
    tiling.set_htMin(*htMin);
    tiling.set_htMax(*htMax);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspace_sizes = context->GetWorkspaceSizes(1);
    workspace_sizes[0] = 0;
    return ge::GRAPH_SUCCESS;
}

